class JWTService:
    @staticmethod
    def _normalize_origin(origin: str) -> str:
        return (origin or "").strip().rstrip("/")

    @staticmethod
    def _is_local_dev_origin(origin: str) -> bool:
        try:
            parsed = urlparse(origin)
