        return {
            "sub": user_id,
            "type": token_type,
            "csrf": csrf_token,
            "iat": now,
            "nbf": now,
            "exp": now + ttl,
            "jti": str(uuid4()),
        }

    @staticmethod
    def _encode_token(claims: dict[str, Any]) -> str:
