            algorithms=[_ALGORITHM],
            options={"require": ["sub", "type", "csrf", "iat", "nbf", "exp", "jti"]},
        )

    @staticmethod
    def _set_jwt_cookie(response: Response, name: str, token: str, ttl: timedelta) -> None:
