from __future__ import annotations

import json
import logging
from dataclasses import dataclass
from typing import Literal
from urllib.parse import urlparse

from server.config import BaseConfig, get_app_config
from server.utils.logging import get_app_logger

StartupEntrypoint = Literal["main_app", "game_server"]

_MIN_SECRET_BYTES = 32
_PLACEHOLDER_SECRETS = {
    "change-me",
    "changeme",
    "dev-secret",
    "dev-secret-change-me",
    "secret",
    "test-secret-key-32-bytes-minimum",
    "test-jwt-secret-key-32-bytes-min",
}


@dataclass(frozen=True)
class StartupAlert:
    code: str
    message: str


def _is_testing(cfg: BaseConfig) -> bool:
    return bool(getattr(cfg, "TESTING", False))


def _is_production(cfg: BaseConfig) -> bool:
    return not bool(getattr(cfg, "IS_DEV", False)) and not _is_testing(cfg)


def _secret_alerts(setting_name: str, value: str | None) -> list[StartupAlert]:
    normalized = (value or "").strip()
    if not normalized:
        return [
            StartupAlert(
                code=f"{setting_name.lower()}_missing",
                message=f"{setting_name} is not configured; authenticated traffic is unsafe.",
            )
        ]

    alerts: list[StartupAlert] = []
    if len(normalized.encode("utf-8")) < _MIN_SECRET_BYTES:
        alerts.append(
            StartupAlert(
                code=f"{setting_name.lower()}_too_short",
                message=f"{setting_name} is shorter than {_MIN_SECRET_BYTES} bytes.",
            )
        )
    if normalized.lower() in _PLACEHOLDER_SECRETS:
        alerts.append(
            StartupAlert(
                code=f"{setting_name.lower()}_placeholder",
                message=f"{setting_name} appears to use a development or test placeholder.",
            )
        )
    return alerts


def _is_insecure_public_url(raw_url: str | None) -> bool:
    if not raw_url:
        return False
    parsed = urlparse(raw_url)
    if parsed.scheme == "https":
        return False
    return parsed.hostname not in {"localhost", "127.0.0.1", "::1"}


def _credentials_json_is_configured(raw_value: str | None) -> bool:
    raw = (raw_value or "").strip()
    if not raw:
        return False
    try:
        parsed = json.loads(raw)
    except Exception:
        return False
    return isinstance(parsed, dict) and bool(parsed)


def evaluate_startup_alerts(
    cfg: BaseConfig,
    *,
    entrypoint: StartupEntrypoint,
) -> list[StartupAlert]:
    """
    Return production-safety alerts for risky startup configuration.

    Testing is intentionally quiet so test fixtures can use synthetic credentials
    without producing warnings for every app factory.
    """
    if _is_testing(cfg):
        return []

    alerts: list[StartupAlert] = []
    alerts.extend(_secret_alerts("SECRET_KEY", getattr(cfg, "SECRET_KEY", "")))
    alerts.extend(_secret_alerts("JWT_SECRET_KEY", getattr(cfg, "JWT_SECRET_KEY", "")))

    if _is_production(cfg):
        if not bool(getattr(cfg, "JWT_COOKIE_SECURE", True)):
            alerts.append(
                StartupAlert(
                    code="jwt_cookie_secure_disabled",
                    message="JWT_COOKIE_SECURE is disabled in production.",
                )
            )

        allowed_origins = getattr(cfg, "CORS_ALLOWED_ORIGINS", []) or []
        if "*" in allowed_origins:
            alerts.append(
                StartupAlert(
                    code="cors_all_origins_allowed",
                    message="CORS_ALLOWED_ORIGINS allows every origin in production.",
                )
            )

        for setting_name in (
            "BACKEND_PUBLIC_BASE_URL",
            "GAME_WS_PUBLIC_BASE_URL",
            "CHAT_WS_PUBLIC_BASE_URL",
            "FRONTEND_PUBLIC_BASE_URL",
        ):
            if _is_insecure_public_url(getattr(cfg, setting_name, "")):
                alerts.append(
                    StartupAlert(
                        code=f"{setting_name.lower()}_insecure",
                        message=f"{setting_name} is not HTTPS in production.",
                    )
                )

        if getattr(cfg, "DEV_ADMIN_TOKEN", ""):
            alerts.append(
                StartupAlert(
                    code="dev_admin_token_enabled",
                    message="DEV_ADMIN_TOKEN is configured in production.",
                )
            )

    if entrypoint == "main_app" and _is_production(cfg):
        if not _credentials_json_is_configured(getattr(cfg, "GAME_SERVER_CREDENTIALS_JSON", "")):
            alerts.append(
                StartupAlert(
                    code="game_server_credentials_missing",
                    message="GAME_SERVER_CREDENTIALS_JSON is missing or invalid; game servers cannot authenticate.",
                )
            )

    if entrypoint == "game_server":
        server_id = (getattr(cfg, "GAME_SERVER_SELF_ID", "") or "").strip()
        signing_secret = (getattr(cfg, "GAME_SERVER_SELF_SIGNING_SECRET", "") or "").strip()
        if not server_id:
            alerts.append(
                StartupAlert(
                    code="game_server_self_id_missing",
                    message="GAME_SERVER_SELF_ID is not configured; registry heartbeat will be disabled.",
                )
            )
        if not signing_secret:
            alerts.append(
                StartupAlert(
                    code="game_server_self_signing_secret_missing",
                    message="GAME_SERVER_SELF_SIGNING_SECRET is not configured; registry heartbeat will be disabled.",
                )
            )
        else:
            alerts.extend(_secret_alerts("GAME_SERVER_SELF_SIGNING_SECRET", signing_secret))

    return alerts


def emit_startup_alerts(
    *,
    entrypoint: StartupEntrypoint,
    cfg: BaseConfig | None = None,
    logger: logging.Logger | None = None,
) -> list[StartupAlert]:
    """
    Log startup safety alerts and never raise into application startup.
    """
    app_logger = logger or get_app_logger()
    try:
        resolved_cfg = cfg or get_app_config()
        alerts = evaluate_startup_alerts(resolved_cfg, entrypoint=entrypoint)
    except Exception as exc:
        app_logger.warning("[StartupSafety] Failed to evaluate startup safety alerts: %s", exc)
        return [
            StartupAlert(
                code="startup_alerts_evaluation_failed",
                message=str(exc),
            )
        ]

    for alert in alerts:
        app_logger.warning("[StartupSafety] %s: %s", alert.code, alert.message)

    return alerts

