@health_routes.get("/health")
def health_check(request: Request):
    client_host = request.client.host if request.client else "unknown"
    app_logger.info(f"Health check received from {client_host}")
    return {"status": "ok"}


def _check_config() -> dict[str, str]:
    try:
        cfg = get_app_config()
    except Exception as exc:
        return {"status": "fail", "detail": f"Configuration failed to load: {exc}"}

    missing = [
        setting_name
        for setting_name in ("SECRET_KEY", "JWT_SECRET_KEY")
        if not (getattr(cfg, setting_name, "") or "").strip()
    ]
    short = [
        setting_name
        for setting_name in ("SECRET_KEY", "JWT_SECRET_KEY")
        if 0 < len((getattr(cfg, setting_name, "") or "").encode("utf-8")) < 32
    ]
    if missing:
        return {"status": "fail", "detail": f"Missing required settings: {', '.join(missing)}"}
    if short:
        return {"status": "fail", "detail": f"Settings are too short: {', '.join(short)}"}
    return {"status": "ok"}


def _check_mongodb() -> dict[str, str]:
    try:
        client = MongoDBClient.get_client()
        MongoDBClient.get_db_name()
        if not getattr(MongoDBClient, "_is_mock", False):
            client.admin.command("ping")
    except Exception as exc:
        return {"status": "fail", "detail": f"MongoDB is unavailable: {exc}"}
    return {"status": "ok"}


def _readiness_payload() -> tuple[bool, dict[str, object]]:
    checks = {
        "configuration": _check_config(),
        "mongodb": _check_mongodb(),
    }
    ready = all(check["status"] == "ok" for check in checks.values())
    return ready, {
        "status": "ready" if ready else "not_ready",
        "checks": checks,
    }


@health_routes.get("/health/ready")
def readiness_check():
    ready, payload = _readiness_payload()
    if ready:
        return payload
    return JSONResponse(status_code=503, content=payload)

